 #[test]
 fn test_process_batch() {
     let pipeline = make_pipeline(default_config());
     let files = vec![
         SourceFile {
             content: "File one content here.".into(),
             metadata: test_meta("txt"),
         },
         SourceFile {
             content: "File two content here.".into(),
             metadata: SourceMetadata {
                 file_path: "other.txt".into(),
                 extension: "txt".into(),
                 language: None,
                 scope_id: "test".into(),
                 source_version: "v1".into(),
             },
         },
     ];
     let (chunks, report) = pipeline.process_batch(&files).unwrap();
     assert!(!chunks.is_empty());
     assert_eq!(report.files_processed, 2);
     assert!(report.total_chunks >= 2);
 }

 #[test]
 fn test_process_overlap_context() {
     let config = ChunkingConfig {
         max_tokens: 10, // force splitting
         min_tokens: 2,
         overlap_tokens: 2, // 2 tokens = ~8 chars overlap
         strategy: "auto".into(),
     };
     let pipeline = make_pipeline(config);
     let source = "First paragraph with some content.\n\nSecond paragraph with more content.\n\nThird paragraph with final content.";
     let chunks = pipeline.process(source, &test_meta("txt")).unwrap();
     if chunks.len() >= 2 {
         // Second chunk onward should have overlap applied
         let has_overlap = chunks.iter().skip(1).any(|c| c.processing.overlap_tokens > 0);
         assert!(has_overlap, "expected overlap context on subsequent chunks");
     }
 }

